query:
SELECT p.id, p.batchNo, p.productName, p.importedCategoryName, p.importedBrandName, p.categoryId, pc.categoryName, pc.subtypeCode, pc.brandName, p.`currentStationCode`, p.`currentStatus`, p.createdAt, p.updatedAt FROM products p LEFT JOIN product_categories pc ON pc.id = p.categoryId WHERE p.batchNo = '1.01300001569';

SELECT st.id, st.productId, st.`stationCode`, st.`taskStatus`, st.createdAt, st.updatedAt, st.completedAt, st.resultSummary FROM station_tasks st INNER JOIN products p ON p.id = st.productId WHERE p.batchNo = '1.01300001569' ORDER BY st.id ASC;

SELECT csf.id, csf.categoryId, pc.categoryName, pc.brandName, pc.subtypeCode, csf.`stationCode`, csf.stepOrder, csf.active FROM category_station_flows csf INNER JOIN product_categories pc ON pc.id = csf.categoryId INNER JOIN products p ON p.categoryId = csf.categoryId WHERE p.batchNo = '1.01300001569' ORDER BY csf.stepOrder ASC;

